using sv_a5a50409090a42a6a5c2b52370e2b139.Client.Models;
using sv_a5a50409090a42a6a5c2b52370e2b139.Client.Services;

namespace sv_a5a50409090a42a6a5c2b52370e2b139.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with fake shipment data.
/// </summary>
public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.FromHours(-5)),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 22, 9, 0, 0, TimeSpan.FromHours(-5)), "Package picked up", "New York, NY"),
                new(new DateTimeOffset(2026, 5, 23, 14, 30, 0, TimeSpan.FromHours(-5)), "Arrived at sorting facility", "Philadelphia, PA"),
                new(new DateTimeOffset(2026, 5, 24, 6, 15, 0, TimeSpan.FromHours(-6)), "In transit to destination", "Chicago, IL"),
            }),

        ["TRK-002"] = new ShipmentDetails(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 23, 12, 0, 0, TimeSpan.FromHours(-7)),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.FromHours(-7)), "Package picked up", "Los Angeles, CA"),
                new(new DateTimeOffset(2026, 5, 21, 8, 45, 0, TimeSpan.FromHours(-7)), "Arrived at local facility", "San Jose, CA"),
                new(new DateTimeOffset(2026, 5, 22, 11, 0, 0, TimeSpan.FromHours(-7)), "Out for delivery", "San Francisco, CA"),
                new(new DateTimeOffset(2026, 5, 22, 14, 22, 0, TimeSpan.FromHours(-7)), "Delivered — left at front door", "San Francisco, CA"),
            }),

        ["TRK-003"] = new ShipmentDetails(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.FromHours(-5)),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 24, 8, 0, 0, TimeSpan.FromHours(-5)), "Label created, awaiting pickup", "Dallas, TX"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate a slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_a5a50409090a42a6a5c2b52370e2b139.Client.Models
@using sv_a5a50409090a42a6a5c2b52370e2b139.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h2>Shipment Tracking</h2>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <dl>
            <dt>Tracking Number</dt>
            <dd>@_shipment.TrackingNumber</dd>

            <dt>Status</dt>
            <dd>@_shipment.Status</dd>

            <dt>Current Location</dt>
            <dd>@_shipment.Location</dd>

            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h4>Status Updates</h4>
        @if (_shipment.Updates.Count == 0)
        {
            <p>No status updates available.</p>
        }
        else
        {
            <table class="table">
                <thead>
                    <tr>
                        <th>Time</th>
                        <th>Description</th>
                        <th>Location</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var update in _shipment.Updates)
                    {
                        <tr>
                            <td>@update.Timestamp.ToString("g")</td>
                            <td>@update.Description</td>
                            <td>@update.Location</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Cancel any in-flight request when the tracking number changes
        CancelPending();
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        _loading = true;
        _errorMessage = null;
        _shipment = null;

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Request was intentionally cancelled (navigation or dispose); do nothing.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        CancelPending();
        await LoadShipmentAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
